#include <stdio.h>
#include <stdlib.h>
#define MAX_N 64
#define MAX_M 2016

// Function to find an Eulerian path in a graph
void findEulerianPath(int **graph, int *degree, int N, int M) {
    int *path = (int *)malloc(M * sizeof(int));
    int pathLen = 0;
    int *stack = (int *)malloc(N * sizeof(int));
    int stackLen = 0;
    int v = 0;
    while (1) {
        while (degree[v] > 0) {
            stack[stackLen++] = v;
            int u = -1;
            for (int i = 0; i < N; i++) {
                if (graph[v][i] > 0) {
                    u = i;
                    break;
                }
            }
            degree[v]--;
            degree[u]--;
            graph[v][u]--;
            graph[u][v]--;
            v = u;
        }
        if (stackLen == 0) break;
        path[pathLen++] = v;
        v = stack[--stackLen];
    }
    printf("%d", pathLen);
    for (int i = 0; i < pathLen; i++) {
        printf(" %d", path[i] + 1);
    }
    printf("\n");
    free(path);
    free(stack);
}

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N, M;
        scanf("%d %d", &N, &M);
        int **graph = (int **)malloc(N * sizeof(int *));
        for (int i = 0; i < N; i++) {
            graph[i] = (int *)malloc(N * sizeof(int));
            for (int j = 0; j < N; j++) {
                graph[i][j] = 0;
            }
        }
        int *degree = (int *)malloc(N * sizeof(int));
        for (int i = 0; i < N; i++) {
            degree[i] = 0;
        }
        for (int i = 0; i < M; i++) {
            int u, v;
            scanf("%d %d", &u, &v);
            u--;
            v--;
            graph[u][v]++;
            graph[v][u]++;
            degree[u]++;
            degree[v]++;
        }
        findEulerianPath(graph, degree, N, M);
        for (int i = 0; i < N; i++) {
            free(graph[i]);
        }
        free(graph);
        free(degree);
    }
    return 0;
}

